import React from "react"
import { Link } from "gatsby"
import { useLocation } from "@reach/router"

const ServiceSidebar = () => {
  const location = useLocation()

  const isActive = path => {
    // Remove hash from current path for comparison
    const currentPath = location.pathname
    const linkPath = path.split("#")[0]
    return currentPath === linkPath
  }
  return (
    <>
      <div className="services-details-info service-sidebar">
        <ul className="services-list">
          <li>
            <Link
              to="/platforms/assets-management#assets-management"
              getProps={({ href }) => ({
                className: isActive(href) ? "active" : "",
              })}
            >
              Assets Management
            </Link>
          </li>
          <li>
            <Link
              to="/platforms/carbon-market#carbon-market"
              getProps={({ href }) => ({
                className: isActive(href) ? "active" : "",
              })}
            >
              Carbon Market
            </Link>
          </li>

          <li>
            <Link
              to="/platforms/green-it#green-it"
              getProps={({ href }) => ({
                className: isActive(href) ? "active" : "",
              })}
            >
              Green IT
            </Link>
          </li>
        </ul>

        <div className="services-contact-info">
          <div className="text-center  ">
            <h4 className="mt-3">
              <strong>Schedule a Meeting with Us</strong>
            </h4>
            <p className="mb-3">Book a time slot that works best for you.</p>
            <div className="others-option d-flex align-items-center justify-content-center">
              <div className="option-item">
                <a
                  href="https://outlook.office365.com/book/ConnectwithAppNetWise@appnetwise.com/"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="default-btn "
                >
                  <i className="flaticon-calendar mr-4"></i> Book a Demo
                  <span></span>
                </a>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  )
}

export default ServiceSidebar
